<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="cap-width="device-width">
    <title>Bouncing Ball Physics</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background-color: #121212;
            color: #e0e0e0;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            overflow: hidden;
        }

        #sim {
            background-color: #000;
            border: 2px solid #333;
            box-shadow: 0 0 30px rgba(0, 0, 0, 0.5);
            cursor: crosshair;
            display: block;
        }

        .controls {
            margin-top: 20px;
            display: flex;
            gap: 15px;
        }

        button {
            padding: 10px 20px;
            font-size: 14px;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 1px;
            cursor: pointer;
            background-color: #2a2a2a;
            color: #fff;
            border: 1px solid #444;
            border-radius: 4px;
            transition: all 0.2s ease;
        }

        button:hover {
            background-color: #3a3a3a;
            border-color: #666;
        }

        button:active {
            transform: translateY(1px);
            background-color: #1a1a1a;
        }

        #play.playing {
            background-color: #2e7d32;
            border-color: #4caf50;
        }
    </style>
</head>
<body>

    <canvas id="sim" width="600" height="600"></canvas>

    <div class="controls">
        <button id="drop">Drop Ball</button>
        <button id="play">Play</button>
        <button id="clear">Clear</button>
    </div>

    <script>
        (function() {
            const canvas = document.getElementById('sim');
            const ctx = canvas.getContext('2d');
            const dropBtn = document.getElementById('drop');
            const playBtn = document.getElementById('play');
            const clearBtn = document.getElementById('clear');

            const width = canvas.width;
            const height = canvas.height;
            const gravity = 0.25;
            const restitution = 0.85;

            let balls = [];
            let isPlaying = false;
            let animationFrameId = null;

            // Internal Ball Class/Structure logic
            function createBall(x, y, vx = 0, vy = 0, r = 12) {
                const hue = Math.floor(Math.random() * 360);
                return {
                    x: x,
                    y: y,
                    vx: vx,
                    vy: vy,
                    r: r,
                    color: `hsl(${hue}, 80%, 60%)`
                };
            }

            // The required API implementation
            window.sim = {
                w: width,
                h: height,
                balls: function() {
                    // Return a deep copy of ball properties to prevent external mutation
                    return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
                },
                addBall: function(x, y, vx = 0, vy = 0, r) {
                    const ball = createBall(x, y, vx, vy, r);
                    balls.push(ball);
                    this.step(1); // Redraw immediately
                },
                clear: function() {
                    balls = [];
                    this.step(1);
                },
                step: function(dt = 1) {
                    // Physics Update
                    for (let i = 0; i < balls.length; i++) {
                        const b = balls[i];

                        // Apply Gravity
                        b.vy += gravity * dt;

                        // Update Position
                        b.x += b.vx * dt;
                        b.y += b.vy * dt;

                        // Collision: Left/Right Walls
                        if (b.x - b.r < 0) {
                            b.x = b.r;
                            b.vx *= -restitution;
                        } else if (b.x + b.r > width) {
                            b.x = width - b.r;
                            b.vx *= -restitution;
                        }

                        // Collision: Top/Bottom Walls
                        if (b.y - b.r < 0) {
                            b.y = b.r;
                            b.vy *= -restitution;
                        } else if (ball_is_hitting_bottom(b, height)) {
                            b.y = height - b.r;
                            b.vy *= -restitution;
                        }
                    }

                    // Rendering
                    ctx.clearRect(0, 0, width, height);
                    for (let i = 0; i < balls.length; i++) {
                        const b = balls[i];
                        ctx.beginPath();
                        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
                        ctx.fillStyle = b.color;
                        ctx.fill();
                        // Add a little shine for "satisfying" look
                        ctx.strokeStyle = 'rgba(255,255,255,0.3)';
                        ctx.lineWidth = 2;
                        ctx.stroke();
                        ctx.closePath();
                    }
                }
            };

            // Helper for bottom collision check to avoid scope issues in the loop
            function ball_is_hitting_bottom(b, h) {
                return b.y + b.r > h;
            }

            // Animation Loop
            function loop() {
                if (isPlaying) {
                    window.sim.step(1);
                    animationFrameId = requestAnimationFrame(loop);
                }
            }

            // UI Event Listeners
            canvas.addEventListener('mousedown', (e) => {
                const rect = canvas.getBoundingClientRect();
                const x = e.clientX - rect.left;
                const y = e.clientY - rect.top;
                window.sim.addBall(x, y, (Math.random() - 0.5) * 10, (Math.random() - 0.5) * 10);
            });

            dropBtn.addEventListener('click', () => {
                // Drop a ball from the top center with some random horizontal velocity
                window.sim.addBall(width / 2, 50, (Math.random() - 0.5) * 8, 2);
            });

            playBtn.addEventListener('click', () => {
                isPlaying = !isPlaying;
                if (isPlaying) {
                    playBtn.textContent = 'Pause';
                    playBtn.classList.add('playing');
                    loop();
                } else {
                    playBtn.textContent = 'Play';
                    playBtn.classList.remove('playing');
                    cancelAnimationFrame(animationFrameId);
                }
            });

            clearBtn.addEventListener('click', () => {
                window.sim.clear();
            });

            // Initial Draw
            window.sim.step(1);

        })();
    </script>
</body>
</html>
